        assert_eq!(loaded.temp_dir, "/home/test/.buk/temp-20260403");
        assert_eq!(loaded.pid, "12345");
        assert_eq!(loaded.timeout, 300);

        let _ = std::fs::remove_dir_all(&dir);
    }
}

