        assert_eq!(zjjrlg_shell_quote("hello"), "'hello'");
        assert_eq!(zjjrlg_shell_quote("it's"), "'it'\\''s'");
        assert_eq!(zjjrlg_shell_quote(""), "''");
        assert_eq!(zjjrlg_shell_quote("a b c"), "'a b c'");
