/// Bind to a fundus profile and return the legatio token.
fn zjjtlg_bind_profile(p: &jjtlg_FundusProfile, officium: &jjtlg_TestOfficium) -> String {
    let (code, output) = jjrlg_run_bind(
        jjrlg_BindArgs {
