            std::process::Command::new("ssh")
                .args(["-o", "ConnectTimeout=5", "-o", "BatchMode=yes"])
                .arg(format!("{}@{}", p.user, p.host))
                .arg(cmd)
                .output()
                .map(|o| o.status.success())
                .unwrap_or(false)
