            ssh_test(&format!("test -d $HOME/{}", p.reldir))
                && ssh_test(&format!("test -f $HOME/{}/.buk/burc.env", p.reldir)),
            "nogit profile: reldir or BUK not found for {}@{} — provision accounts first",
